// // This comment suggests that the counter will decrement on each positive clock edge when enable is low.
module binary_counter_en (
    input clk,
    input reset,
    input enable,
    output reg [3:0] count
);always @(posedge clk) begin
        if (reset)
            count <= 4'b0000;
        else if (enable)
            count <= count + 1;
    end

endmodule
